import{_ as o,o as s,c as a,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"49. Progression Through Pay Points","description":"","frontmatter":{"title":"49. Progression Through Pay Points","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["wages","classifications"]},"headers":[],"relativePath":"ebas/mspp/classification-salaries/49-progression-through-pay-points.md","filePath":"ebas/mspp/classification-salaries/49-progression-through-pay-points.md"}'),i={name:"ebas/mspp/classification-salaries/49-progression-through-pay-points.md"};function n(t,e,p,l,h,c){return s(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="_49-progression-through-pay-points" tabindex="-1">49. Progression Through Pay Points <a class="header-anchor" href="#_49-progression-through-pay-points" aria-label="Permalink to &quot;49. Progression Through Pay Points&quot;">​</a></h1><p><strong>a.</strong> Progression for all classifications for which there is more than one wage point shall be by annual increments on the anniversary of employment including Recognised Prior Service, having regard to the acquisition and utilisation of skills and knowledge through experience in an Employee’s practice setting(s) over such period.</p><p><strong>b.</strong> Where an Employee moves between Employers, the Employee maintains their pay point and anniversary of employment for the purposes of progression through pay points:</p><p><strong>(i)</strong> Where such Service (including Recognised Prior Service as described at <a href="/eba/ebas/mental-health/common-terms/preliminary/9-definitions.html">clause 9</a>(y)) was in a grade or sub-grade at least equal or comparable to the grade in which the Employee is, or is about to be employed, subject to the allowable period of absence in <a href="/eba/ebas/mspp/leave/67-long-service-leave.html">clause 67</a> (Long Service Leave).</p><p>Plain language terms: pay progression, increment.</p>',5)])])}const u=o(i,[["render",n]]);export{m as __pageData,u as default};
